def max_subarray_with_indices(nums):
    max_sum = current = nums[0]
    start = end = temp_start = 0
    for i in range(1, len(nums)):
        if nums[i] > current + nums[i]:
            current = nums[i]
            temp_start = i
        else:
            current += nums[i]
        if current > max_sum:
            max_sum, start, end = current, temp_start, i
    return max_sum, nums[start:end+1]

