class Main {
    static class TreeNode { int val; TreeNode l,r; TreeNode(int v){val=v;} }

    // #102 層序遍歷
    static List<List<Integer>> levelOrder(TreeNode root) {
        List<List<Integer>> res = new ArrayList<>();
        if (root==null) return res;
        Queue<TreeNode> q = new LinkedList<>();
        q.offer(root);
        while (!q.isEmpty()) {
            int sz = q.size();
            List<Integer> lvl = new ArrayList<>();
            for (int i=0;i<sz;i++) {
                TreeNode n=q.poll(); lvl.add(n.val);
                if(n.l!=null)q.offer(n.l); if(n.r!=null)q.offer(n.r);
            }
            res.add(lvl);
        }
        return res;
    }

    // #104 最大深度
    static int maxDepth(TreeNode root) {
        return root==null ? 0 : 1+Math.max(maxDepth(root.l),maxDepth(root.r));
    }

    // #112 路徑總和
    static boolean hasPathSum(TreeNode root, int target) {
        if (root==null) return false;
        if (root.l==null && root.r==null) return root.val==target;
        return hasPathSum(root.l,target-root.val)||hasPathSum(root.r,target-root.val);
    }

    public static void main(String[] args) {
        TreeNode root = new TreeNode(5);
        root.l=new TreeNode(4); root.r=new TreeNode(8);
        root.l.l=new TreeNode(11); root.l.l.l=new TreeNode(7); root.l.l.r=new TreeNode(2);
        root.r.l=new TreeNode(13); root.r.r=new TreeNode(4); root.r.r.r=new TreeNode(1);
        System.out.println(levelOrder(root));
        System.out.println("MaxDepth: "+maxDepth(root));
        System.out.println("PathSum 22: "+hasPathSum(root,22));
    }
}

