// #167 有序陣列雙指針（更簡單）
void two_sum_sorted(int* nums, int n, int target, int* i1, int* i2) {
    int l=0, r=n-1;
    while(l<r) {
        int s=nums[l]+nums[r];
        if(s==target){*i1=l+1;*i2=r+1;return;}
        else if(s<target) l++;
        else r--;
    }
    *i1=*i2=-1;
}

// #1 無序雜湊表（開放定址）
#define SZ 4096
int ht_key[SZ]; int ht_val[SZ]; int ht_use[SZ];
void ht_clear(){memset(ht_use,0,sizeof(ht_use));}
void ht_set(int k,int v){int i=((unsigned)k*2654435761u)%SZ;while(ht_use[i]&&ht_key[i]!=k)i=(i+1)%SZ;ht_key[i]=k;ht_val[i]=v;ht_use[i]=1;}
int ht_get(int k,int*ok){int i=((unsigned)k*2654435761u)%SZ;while(ht_use[i]){if(ht_key[i]==k){*ok=1;return ht_val[i];}i=(i+1)%SZ;}*ok=0;return -1;}

void two_sum(int* nums, int n, int target, int* r1, int* r2) {
    ht_clear();
    for(int i=0;i<n;i++){
        int comp=target-nums[i],ok,j=ht_get(comp,&ok);
        if(ok){*r1=j;*r2=i;return;}
        ht_set(nums[i],i);
    }
    *r1=*r2=-1;
}

int main() {
    int sorted[]={2,7,11,15}; int i1,i2;
    two_sum_sorted(sorted,4,9,&i1,&i2);
    printf("sorted: [%d,%d]\n",i1,i2); // [1,2]
    int unsorted[]={3,2,4};
    two_sum(unsorted,3,6,&i1,&i2);
    printf("unsorted: [%d,%d]\n",i1,i2); // [1,2]
    return 0;
}
